
(function(global) {
  class AxomCSS {
    constructor(config) {
      this.config = {
        colors: {
          primary: '#3b82f6', secondary: '#10b981', accent: '#f59e0b',
          background: '#ffffff', surface: '#f3f4f6', text: '#1f2933',
          red: '#ef4444', orange: '#f97316', amber: '#f59e0b', yellow: '#eab308',
          lime: '#84cc16', green: '#22c55e', emerald: '#10b981', teal: '#14b8a6',
          cyan: '#06b6d4', sky: '#0ea5e9', blue: '#3b82f6', indigo: '#6366f1',
          violet: '#8b5cf6', purple: '#a855f7', fuchsia: '#d946ef', pink: '#ec4899',
          rose: '#f43f5e', gray: '#6b7280', slate: '#64748b', zinc: '#71717a',
          neutral: '#737373', stone: '#78716c', white: '#ffffff', black: '#000000',
          transparent: 'transparent', current: 'currentColor',
          ...config?.colors
        },
        spacing: config?.spacing || 'rem',
        borderRadius: config?.borderRadius || 'md',
        fontFamily: config?.fontFamily || 'system-ui, -apple-system, sans-serif',
        fontSize: config?.fontSize || { sm: '0.875rem', base: '1rem', lg: '1.125rem', xl: '1.25rem', '2xl': '1.5rem', '3xl': '1.875rem', '4xl': '2.25rem' },
        fontWeight: config?.fontWeight || { thin: '100', light: '300', normal: '400', medium: '500', semibold: '600', bold: '700', extrabold: '800' },
        screens: config?.screens || { sm: '640px', md: '768px', lg: '1024px', xl: '1280px', '2xl': '1536px' },
        animation: config?.animation || { none: 'none', spin: 'spin 1s linear infinite', ping: 'ping 1s cubic-bezier(0,0,0.2,1) infinite', pulse: 'pulse 2s cubic-bezier(0.4,0,0.6,1) infinite', bounce: 'bounce 1s infinite' },
        ...config
      };
      this.cache = new Map();
      this.listeners = new Set();
      this.themes = new Map();
      this.initThemes();
      if (typeof document !== 'undefined') this.init();
    }

    initThemes() {
      this.themes.set('light', {
        colors: { background: '#ffffff', surface: '#f3f4f6', text: '#1f2933', primary: '#3b82f6', secondary: '#10b981' }
      });
      this.themes.set('dark', {
        colors: { background: '#1f2937', surface: '#374151', text: '#f9fafb', primary: '#60a5fa', secondary: '#34d399' }
      });
      this.themes.set('ocean', {
        colors: { background: '#e0f2fe', surface: '#bae6fd', text: '#0c4a6e', primary: '#0284c7', secondary: '#0891b2' }
      });
      this.themes.set('forest', {
        colors: { background: '#ecfdf5', surface: '#d1fae5', text: '#064e3b', primary: '#059669', secondary: '#10b981' }
      });
      this.themes.set('sunset', {
        colors: { background: '#fff7ed', surface: '#ffedd5', text: '#7c2d12', primary: '#ea580c', secondary: '#f97316' }
      });
      this.themes.set('midnight', {
        colors: { background: '#0f172a', surface: '#1e293b', text: '#e2e8f0', primary: '#818cf8', secondary: '#c084fc' }
      });
      this.themes.set('corporate', {
        colors: { background: '#f8fafc', surface: '#f1f5f9', text: '#0f172a', primary: '#1e40af', secondary: '#475569' }
      });
      this.themes.set('neon', {
        colors: { background: '#000000', surface: '#1a1a1a', text: '#00ff00', primary: '#00ff00', secondary: '#ff00ff' }
      });
      this.themes.set('pastel', {
        colors: { background: '#fdf2f8', surface: '#fce7f3', text: '#831843', primary: '#ec4899', secondary: '#f472b6' }
      });
      this.themes.set('high-contrast', {
        colors: { background: '#000000', surface: '#000000', text: '#ffffff', primary: '#ffff00', secondary: '#00ffff' }
      });
    }

    init() {
      let style = document.getElementById('axomcss-runtime');
      if (!style) {
        style = document.createElement('style');
        style.id = 'axomcss-runtime';
        document.head.appendChild(style);
      }
      this.sheet = style.sheet;
      this.injectBase();
      this.injectKeyframes();
      this.injectComponents();
    }

    injectKeyframes() {
      this.injectRule('@keyframes spin', 'from{transform:rotate(0deg)}to{transform:rotate(360deg)}');
      this.injectRule('@keyframes ping', '75%,100%{transform:scale(2);opacity:0}');
      this.injectRule('@keyframes pulse', '0%,100%{opacity:1}50%{opacity:.5}');
      this.injectRule('@keyframes bounce', '0%,100%{transform:translateY(-25%);animation-timing-function:cubic-bezier(0.8,0,1,1)}50%{transform:translateY(0);animation-timing-function:cubic-bezier(0,0,0.2,1)}');
      this.injectRule('@keyframes slideIn', 'from{transform:translateX(-100%)}to{transform:translateX(0)}');
      this.injectRule('@keyframes slideOut', 'from{transform:translateX(0)}to{transform:translateX(100%)}');
      this.injectRule('@keyframes fadeIn', 'from{opacity:0}to{opacity:1}');
      this.injectRule('@keyframes fadeOut', 'from{opacity:1}to{opacity:0}');
      this.injectRule('@keyframes scaleIn', 'from{transform:scale(0)}to{transform:scale(1)}');
      this.injectRule('@keyframes rotateIn', 'from{transform:rotate(-180deg)}to{transform:rotate(0)}');
      this.injectRule('@keyframes shimmer', '0%{background-position:-1000px 0}100%{background-position:1000px 0}');
      this.injectRule('@keyframes wobble', '0%,100%{transform:translateX(0)}25%{transform:translateX(-5px)}75%{transform:translateX(5px)}');
    }

    injectComponents() {
      this.injectRule('.card', 'background:var(--color-surface);border-radius:var(--radius);padding:1.5rem;box-shadow:0 4px 6px rgba(0,0,0,0.1);transition:all 0.3s');
      this.injectRule('.card:hover', 'transform:translateY(-2px);box-shadow:0 10px 15px rgba(0,0,0,0.1)');
      this.injectRule('.btn', 'padding:0.5rem 1rem;border-radius:var(--radius);font-weight:500;transition:all 0.2s;cursor:pointer;border:none');
      this.injectRule('.btn-primary', 'background:var(--color-primary);color:white');
      this.injectRule('.btn-primary:hover', 'filter:brightness(0.9);transform:translateY(-1px)');
      this.injectRule('.btn-secondary', 'background:var(--color-secondary);color:white');
      this.injectRule('.modal', 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:var(--color-surface);border-radius:var(--radius);padding:2rem;box-shadow:0 20px 25px rgba(0,0,0,0.2);z-index:1000');
      this.injectRule('.modal-backdrop', 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:999');
      this.injectRule('.container', 'max-width:1280px;margin:0 auto;padding:0 1rem');
      this.injectRule('.container-sm', 'max-width:640px;margin:0 auto;padding:0 1rem');
      this.injectRule('.container-lg', 'max-width:1536px;margin:0 auto;padding:0 1rem');
      this.injectRule('.badge', 'display:inline-block;padding:0.25rem 0.5rem;border-radius:9999px;font-size:0.75rem;font-weight:500');
      this.injectRule('.badge-primary', 'background:var(--color-primary);color:white');
      this.injectRule('.alert', 'padding:1rem;border-radius:var(--radius);margin-bottom:1rem');
      this.injectRule('.alert-info', 'background:#e0f2fe;color:#0c4a6e;border-left:4px solid #0284c7');
      this.injectRule('.alert-success', 'background:#d1fae5;color:#064e3b;border-left:4px solid #059669');
      this.injectRule('.alert-warning', 'background:#fed7aa;color:#7c2d12;border-left:4px solid #ea580c');
      this.injectRule('.alert-error', 'background:#fee2e2;color:#991b1b;border-left:4px solid #dc2626');
    }

    injectBase() {
      this.injectRule(':root', `
        ${Object.entries(this.config.colors).map(([k, v]) => `--color-${k}: ${v};`).join('')}
        --spacing-unit: ${this.config.spacing === 'rem' ? '0.25rem' : '4px'};
        --radius-sm: 0.125rem; --radius-md: 0.375rem; --radius-lg: 0.5rem; --radius-xl: 0.75rem; --radius-2xl: 1rem; --radius-full: 9999px;
        --font-sans: ${this.config.fontFamily}; --font-mono: 'Courier New', monospace;
        --shadow-sm: 0 1px 2px 0 rgba(0,0,0,0.05); --shadow-md: 0 4px 6px -1px rgba(0,0,0,0.1); --shadow-lg: 0 10px 15px -3px rgba(0,0,0,0.1); --shadow-xl: 0 20px 25px -5px rgba(0,0,0,0.1); --shadow-2xl: 0 25px 50px -12px rgba(0,0,0,0.25);
        --blur-sm: blur(4px); --blur-md: blur(8px); --blur-lg: blur(12px); --blur-xl: blur(16px);
      `);
      this.injectRule('*', 'box-sizing:border-box;margin:0;padding:0');
      this.injectRule('body', `font-family:${this.config.fontFamily};background:var(--color-background);color:var(--color-text);line-height:1.5`);
      this.injectRule('button,a,input,select,textarea', 'font-family:inherit');
      this.injectRule('button:focus-visible,a:focus-visible,input:focus-visible', 'outline:2px solid var(--color-primary);outline-offset:2px');
      this.injectRule('img,picture,video,canvas,svg', 'display:block;max-width:100%');
      this.injectRule('input,textarea,select', 'padding:0.5rem;border:1px solid var(--color-gray);border-radius:var(--radius-md);background:var(--color-surface)');
      this.injectRule('table', 'width:100%;border-collapse:collapse');
      this.injectRule('th,td', 'padding:0.75rem;text-align:left;border-bottom:1px solid var(--color-gray)');
      this.injectRule('@media (prefers-reduced-motion:reduce)', '*,*::before,*::after{animation-duration:0.01ms!important;transition-duration:0.01ms!important}');
    }

    injectRule(selector, css) {
      try {
        if (this.sheet) this.sheet.insertRule(`${selector}{${css}}`, this.sheet.cssRules.length);
      } catch(e) {}
    }

    cx(...classes) {
      const resolved = new Map();
      for (const cls of classes.filter(Boolean)) {
        for (const [prop, val] of this.parse(cls)) {
          resolved.set(prop, val);
        }
      }
      const final = Array.from(resolved.entries()).map(([p, v]) => `${p}-${v.replace(/\s/g, '_')}`).join(' ');
      this.ensureStyles(final);
      return final;
    }

    parse(cls) {
      const result = new Map();
      const parts = cls.split(/\s+/);
      for (const part of parts) {
        if (part.includes(':')) {
          const [cat, ...mods] = part.split(':');
          const mod = mods.join(':');
          if (cat === 'flex') {
            if (mod === 'center between') result.set('display-align-justify', 'flex center space-between');
            else if (mod === 'center') result.set('align-items', 'center');
            else if (mod === 'between') result.set('justify-content', 'space-between');
            else if (mod === 'col') result.set('flex-direction', 'column');
            else if (mod === 'row') result.set('flex-direction', 'row');
            else if (mod === 'wrap') result.set('flex-wrap', 'wrap');
            else if (mod === '1') result.set('flex', '1');
            else result.set('display', 'flex');
          }
          else if (cat === 'grid') {
            if (mod === 'cols-2') result.set('grid-template-columns', 'repeat(2,1fr)');
            else if (mod === 'cols-3') result.set('grid-template-columns', 'repeat(3,1fr)');
            else if (mod === 'cols-4') result.set('grid-template-columns', 'repeat(4,1fr)');
            else if (mod === 'cols-6') result.set('grid-template-columns', 'repeat(6,1fr)');
            else if (mod === 'cols-12') result.set('grid-template-columns', 'repeat(12,1fr)');
            else result.set('display', 'grid');
          }
          else if (cat === 'p') result.set('padding', this.toSpacing(mod));
          else if (cat === 'm') result.set('margin', this.toSpacing(mod));
          else if (cat === 'px') result.set('padding-left', this.toSpacing(mod));
          else if (cat === 'py') result.set('padding-top', this.toSpacing(mod));
          else if (cat === 'mx') result.set('margin-left', this.toSpacing(mod));
          else if (cat === 'my') result.set('margin-top', this.toSpacing(mod));
          else if (cat === 'pt') result.set('padding-top', this.toSpacing(mod));
          else if (cat === 'pr') result.set('padding-right', this.toSpacing(mod));
          else if (cat === 'pb') result.set('padding-bottom', this.toSpacing(mod));
          else if (cat === 'pl') result.set('padding-left', this.toSpacing(mod));
          else if (cat === 'mt') result.set('margin-top', this.toSpacing(mod));
          else if (cat === 'mr') result.set('margin-right', this.toSpacing(mod));
          else if (cat === 'mb') result.set('margin-bottom', this.toSpacing(mod));
          else if (cat === 'ml') result.set('margin-left', this.toSpacing(mod));
          else if (cat === 'bg') result.set('background-color', `var(--color-${mod})`);
          else if (cat === 'text') {
            if (mod.startsWith('size-')) result.set('font-size', this.toFontSize(mod.replace('size-', '')));
            else if (mod.startsWith('weight-')) result.set('font-weight', this.toFontWeight(mod.replace('weight-', '')));
            else result.set('color', `var(--color-${mod})`);
          }
          else if (cat === 'font') result.set('font-family', mod === 'mono' ? 'var(--font-mono)' : 'var(--font-sans)');
          else if (cat === 'rounded') result.set('border-radius', this.toRadius(mod));
          else if (cat === 'shadow') result.set('box-shadow', this.toShadow(mod));
          else if (cat === 'blur') result.set('filter', `blur(${mod === 'sm' ? '4px' : mod === 'md' ? '8px' : mod === 'lg' ? '12px' : '16px'})`);
          else if (cat === 'transition') {
            if (mod === 'all') result.set('transition', 'all 0.3s ease');
            else if (mod === 'fast') result.set('transition-duration', '150ms');
            else if (mod === 'slow') result.set('transition-duration', '500ms');
            else result.set('transition-property', mod);
          }
          else if (cat === 'animate') {
            if (mod === 'spin') result.set('animation', 'spin 1s linear infinite');
            else if (mod === 'ping') result.set('animation', 'ping 1s cubic-bezier(0,0,0.2,1) infinite');
            else if (mod === 'pulse') result.set('animation', 'pulse 2s cubic-bezier(0.4,0,0.6,1) infinite');
            else if (mod === 'bounce') result.set('animation', 'bounce 1s infinite');
            else if (mod === 'slide-in') result.set('animation', 'slideIn 0.3s ease-out');
            else if (mod === 'fade-in') result.set('animation', 'fadeIn 0.3s ease-out');
            else if (mod === 'scale-in') result.set('animation', 'scaleIn 0.2s ease-out');
          }
          else if (cat === 'hover') {
            for (const [k, v] of this.parse(mod)) result.set(`${k}-hover`, v);
          }
          else if (cat === 'focus') {
            for (const [k, v] of this.parse(mod)) result.set(`${k}-focus`, v);
          }
          else if (cat === 'active') {
            for (const [k, v] of this.parse(mod)) result.set(`${k}-active`, v);
          }
          else if (cat === 'sm' || cat === 'md' || cat === 'lg' || cat === 'xl' || cat === '2xl') {
            const breakpoint = this.config.screens[cat];
            if (breakpoint) {
              for (const [k, v] of this.parse(mod)) result.set(`${k}@${cat}`, v);
            }
          }
          else if (cat === 'dark') result.set('dark-mode', mod);
          else result.set(cat, mod);
        } else {
          const match = part.match(/^([a-z]+)(?:-([a-z0-9]+))?$/);
          if (match) {
            const [, prop, val] = match;
            if (prop === 'p') result.set('padding', this.toSpacing(val || '4'));
            else if (prop === 'm') result.set('margin', this.toSpacing(val || '4'));
            else if (prop === 'text') result.set('color', `var(--color-${val || 'text'})`);
            else if (prop === 'bg') result.set('background-color', `var(--color-${val || 'surface'})`);
            else if (prop === 'flex') result.set('display', 'flex');
            else if (prop === 'grid') result.set('display', 'grid');
            else if (prop === 'hidden') result.set('display', 'none');
            else if (prop === 'block') result.set('display', 'block');
            else if (prop === 'inline') result.set('display', 'inline');
            else if (prop === 'inline-block') result.set('display', 'inline-block');
            else if (prop === 'relative') result.set('position', 'relative');
            else if (prop === 'absolute') result.set('position', 'absolute');
            else if (prop === 'fixed') result.set('position', 'fixed');
            else if (prop === 'sticky') result.set('position', 'sticky');
            else if (prop === 'top-0') result.set('top', '0');
            else if (prop === 'right-0') result.set('right', '0');
            else if (prop === 'bottom-0') result.set('bottom', '0');
            else if (prop === 'left-0') result.set('left', '0');
            else if (prop === 'w-full') result.set('width', '100%');
            else if (prop === 'h-full') result.set('height', '100%');
            else if (prop === 'w-screen') result.set('width', '100vw');
            else if (prop === 'h-screen') result.set('height', '100vh');
            else if (prop === 'rounded') result.set('border-radius', this.toRadius(val || 'md'));
            else if (prop === 'shadow') result.set('box-shadow', this.toShadow(val || 'md'));
          }
        }
      }
      return result;
    }

    toSpacing(val) {
      const parts = val.split('/');
      const num = parseInt(parts[0]) || 0;
      const divisor = parts[1] ? parseInt(parts[1]) : 1;
      const scale = [0, 0.25, 0.5, 0.75, 1, 1.25, 1.5, 2, 2.5, 3, 4, 5, 6, 8, 10, 12, 16, 20, 24, 32, 40, 48, 56, 64];
      return `${(scale[num] || num) / divisor}rem`;
    }

    toRadius(val) {
      const radii = { none: '0', sm: 'var(--radius-sm)', md: 'var(--radius-md)', lg: 'var(--radius-lg)', xl: 'var(--radius-xl)', '2xl': 'var(--radius-2xl)', full: 'var(--radius-full)' };
      return radii[val] || radii.md;
    }

    toShadow(val) {
      const shadows = { sm: 'var(--shadow-sm)', md: 'var(--shadow-md)', lg: 'var(--shadow-lg)', xl: 'var(--shadow-xl)', '2xl': 'var(--shadow-2xl)', none: 'none' };
      return shadows[val] || shadows.md;
    }

    toFontSize(val) {
      const sizes = { xs: '0.75rem', sm: '0.875rem', base: '1rem', lg: '1.125rem', xl: '1.25rem', '2xl': '1.5rem', '3xl': '1.875rem', '4xl': '2.25rem', '5xl': '3rem', '6xl': '4rem' };
      return sizes[val] || sizes.base;
    }

    toFontWeight(val) {
      const weights = { thin: '100', light: '300', normal: '400', medium: '500', semibold: '600', bold: '700', extrabold: '800', black: '900' };
      return weights[val] || weights.normal;
    }

    ensureStyles(cls) {
      if (this.cache.has(cls)) return;
      const styles = this.parse(cls);
      let css = '';
      for (const [prop, val] of styles) {
        if (prop.includes('-hover')) css += `${prop.replace('-hover', '')}: ${val}; `;
        else if (prop.includes('-focus')) css += `${prop.replace('-focus', '')}: ${val}; `;
        else if (prop.includes('-active')) css += `${prop.replace('-active', '')}: ${val}; `;
        else css += `${prop}: ${val}; `;
      }
      if (css) {
        this.injectRule(`.${cls.replace(/[^a-zA-Z0-9_-]/g, '\\$&')}`, css);
        this.cache.set(cls, css);
      }
    }

    get theme() {
      return {
        set: (config) => {
          Object.assign(this.config, config);
          if (config.colors) Object.assign(this.config.colors, config.colors);
          this.injectRule(':root', Object.entries(this.config.colors).map(([k, v]) => `--color-${k}: ${v};`).join(''));
          this.listeners.forEach(l => l(this.config));
        },
        get: () => ({ ...this.config }),
        setTheme: (name) => {
          const theme = this.themes.get(name);
          if (theme) this.theme.set(theme);
        },
        addTheme: (name, config) => { this.themes.set(name, config); },
        listThemes: () => Array.from(this.themes.keys()),
        addScoped: (selector, overrides) => {
          this.injectRule(selector, Object.entries(overrides.colors || {}).map(([k, v]) => `--color-${k}: ${v};`).join(''));
        },
        watch: (cb) => { this.listeners.add(cb); return () => this.listeners.delete(cb); }
      };
    }

    addUtility(name, css) { this.injectRule(`.${name}`, css); this.cache.set(name, css); }
    
    addComponent(name, css) { this.injectRule(`.${name}`, css); }
    
    purge() {
      const used = new Set();
      document.querySelectorAll('[class]').forEach(el => {
        el.className.split(/\s+/).forEach(c => used.add(c));
      });
      for (let i = (this.sheet?.cssRules.length || 0) - 1; i >= 0; i--) {
        const rule = this.sheet?.cssRules[i];
        if (rule?.selectorText?.startsWith('.')) {
          const cls = rule.selectorText.slice(1);
          if (!used.has(cls) && !this.cache.has(cls)) this.sheet?.deleteRule(i);
        }
      }
    }

    async build() {
      let css = '';
      for (let i = 0; i < (this.sheet?.cssRules.length || 0); i++) {
        css += this.sheet?.cssRules[i].cssText;
      }
      return css;
    }
  }

  const axom = new AxomCSS();
  global.axom = axom;
  global.AxomCSS = AxomCSS;
})(window);
